using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change #1: Discriminator property renamed to "$type".
            // Preserve "Discriminator" to remain compatible with existing 500K documents
            // and direct SQL queries that reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // EF Core 9 breaking change #2: Id format changed from "EntityType|Key" to
            // just the key value. Preserve the old format for existing documents.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");
            entity.UsePropertyAccessMode(PropertyAccessMode.Property);

            // EF Core 9 breaking change #3: HasIndex is no longer supported on Cosmos.
            // Cosmos indexes are managed at the container level, not by EF.
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 breaking change #4: Sync I/O now throws by default.
        // Opt back in if you cannot migrate all callers to async yet.
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

